import{_ as t,o as n,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"47. Avoidance And Management Of Short Shifts","description":"","frontmatter":{"title":"47. Avoidance And Management Of Short Shifts","eba":"Nurses and Midwives 2024-2028","topics":["hours","shift-work"]},"headers":[],"relativePath":"ebas/nurses-midwives/hours-of-work/47-avoidance-and-management-of-short-shifts.md","filePath":"ebas/nurses-midwives/hours-of-work/47-avoidance-and-management-of-short-shifts.md"}'),s={name:"ebas/nurses-midwives/hours-of-work/47-avoidance-and-management-of-short-shifts.md"};function r(i,e,h,p,l,c){return n(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_47-avoidance-and-management-of-short-shifts" tabindex="-1">47. Avoidance And Management Of Short Shifts <a class="header-anchor" href="#_47-avoidance-and-management-of-short-shifts" aria-label="Permalink to &quot;47. Avoidance And Management Of Short Shifts&quot;">​</a></h1><p><strong>47.1</strong> Meaning of &#39;Short Shift&#39;</p><p>Short Shift is defined at <a href="/eba/ebas/allied-health/preliminary/4-definitions.html">clause 4</a> (Definitions).</p><p><strong>47.2</strong> No short shifts on night duty</p><p>Short Shifts must not be utilised on night duty.</p><p><strong>47.3</strong> Use of short shifts</p><p><strong>(a)</strong> Except as provided at clauses 47.5, 47.7 and 47.8 below, up to two Short Shifts may be used for a ward or unit per day using no more than two of the following:</p><p><strong>(i)</strong> one &#39;AM&#39; shift (commencing and concluding within the &#39;AM&#39; shift); and/or</p><p><strong>(ii)</strong> one &#39;PM&#39; shift (commencing and concluding within the &#39;PM&#39; shift); and/or</p><p><strong>(iii)</strong> one cross over shift, being a shift that commences before 12.00pm and concludes during the &#39;PM&#39; shift.</p><p><strong>(b)</strong> These limitations do not apply to Short Shifts in addition to ratios.</p><p><strong>(c)</strong> No existing shift length as at the commencement date of this Agreement will be reduced by the operation of (b) above.</p><p><strong>47.4</strong> Short shifts only by agreement</p><p><strong>(a)</strong> An Employee will not be rostered to work Short Shifts unless the Employee agrees to work them.</p><p><strong>(b)</strong> An Employee working a Short Shift arrangement may cease that arrangement by giving 28 days&#39; written notice to the Employer that they wish to work full shift lengths and the arrangement will cease in the next roster or, if a roster has already been posted in accordance with <a href="/eba/ebas/nurses-midwives/hours-of-work/45-rosters.html">clause 45.1</a>, the following roster posted.</p><p><strong>(c)</strong> Nothing in this clause allows for the unilateral changing of an Employee&#39;s contract of employment.</p><p><strong>47.5</strong> Replacement of rostered shift/s</p><p><strong>(a)</strong> Considerations in the use of replacement shifts</p><p><strong>(i)</strong> The Employer will use a full shift to replace unplanned vacancies unless, after making a reasonable effort as described at <a href="/eba/ebas/nurses-midwives/hours-of-work/45-rosters.html">clause 45.8</a> (Replacing unplanned absences) to fill the vacancy on the roster with a permanent Employee, the Employer has not been successful in which case subclause 47.5(b) below applies.</p><p><strong>(ii)</strong> The Employer must use a nurse bank Employee or, if unsuccessful, an agency staff member at the full shift length, except where the nurse in charge of the ward determines a Short Shift will not have a negative impact on patient care, safe staffing and related matters, having regard to all the circumstances on the relevant ward/unit including:</p><p><strong>(A)</strong> patient safety/acuity;</p><p><strong>(B)</strong> skill mix;</p><p><strong>(C)</strong> the time at which the absence was notified;</p><p><strong>(D)</strong> whether the ward/unit is staffing above the ratios under the Safe Patient Care Act;</p><p><strong>(E)</strong> the number of short shifts on the ward;</p><p><strong>(F)</strong> the nature of any professional development being provided by the Employer;</p><p><strong>(G)</strong> the capacity for Employees to attend professional development; and</p><p><strong>(H)</strong> whether there is any pre-arranged education for casual staff.</p><p><strong>(b)</strong> Other options</p><p>Nothing in this clause prevents an Employer replacing an unplanned absence on the roster with a longer shift than a Short Shift.</p><p><strong>47.6</strong> ADOs (full-time Employees)</p><p>A full-time Employee who works a Short Shift will be entitled to an ADO as if a full shift was worked.</p><p><strong>47.7</strong> Exception – workload management proposal</p><p><strong>(a)</strong> Short Shifts may be rostered beyond the limit specified at clause 47.3 where it forms part of an EFT neutral workload management proposal implemented under <a href="/eba/ebas/nurses-midwives/classification-staffing/93-proposals-to-vary-specific-matters.html">clause 93</a> of this Agreement (Proposals to Vary Specific Matters).</p><p><strong>(b)</strong> A workload management proposal to roster short shifts beyond the limit specified at clause 47.3 that is not EFT neutral cannot be made under this Agreement.</p><p><strong>47.8</strong> Limited Exception – aged care and rehabilitation units</p><p><strong>(a)</strong> The exception that applied to aged care and rehabilitation wards under clause</p><p><strong>47.8</strong> of the 2020 Agreement will continue to apply subject to the following:</p><p><strong>(i)</strong> If the Employer seeks to maintain the exception, notify the Central Implementation Committee in writing (at <a href="/eba/ebas/nurses-midwives/union-matters/80-union-matters.html">clause 80</a>) by no later than 6 months from the Agreement coming into operation, following which it will be considered in accordance with subclause 47.8(b) below.</p><p><strong>(ii)</strong> If the Employer does not advise the Central Implementation Committee in writing within 6 months of the Agreement coming into operation, the exception ceases to have effect, and the limits on Short Shifts prescribed in clause 47 above will apply.</p><p><strong>(b)</strong> Where the Central Implementation Committee receives a notification under subclause 47.8(a)(ii), it will consider whether it supports the continuation of the exception taking into account all the circumstances including, but not limited to:</p><p><strong>(i)</strong> The preference of Employees in the relevant ward/unit;</p><p><strong>(ii)</strong> The preference of Employees working short shifts; and</p><p><strong>(iii)</strong> The operational requirements of the Employer.</p><p><strong>(c)</strong> In the event that the Central Implementation Committee cannot reach a decision, the matter will be resolved in accordance with <a href="/eba/ebas/nurses-midwives/consultation-disputes/14-statewide-industry-panel.html">clause 14</a> (Statewide Industry Panel) on the basis of whether it is reasonable in all the circumstances for the existing exception to continue.</p><p>Note: The exception at clause 47.8 applied only to aged care and rehabilitation units that, as of 31 March 2012, had Short Shift arrangements in place for more than two Short Shifts per day and, under the exception, could use up to three Short Shifts per ward or unit in any configuration over the AM and PM shifts.</p><p>Plain language terms: short shift, back to back shifts.</p>',47)])])}const d=t(s,[["render",r]]);export{g as __pageData,d as default};
